<template>
  <div class="carne">
       <div class="col-md-12 text-right mt-3">
             <button type="button" class="btn btn-primary noprint" @click="back">
               <i class="fas fa-arrow-circle-left"></i>
                Voltar
             </button>
             <button type="button" class="btn btn-primary noprint ml-2" @click="print">
               <i class="fas fa-print"></i>
               Imprimir
            </button>
       </div>  
       <div v-for="invoice in invoices" :key="invoice.id" class="mb-5" v-show="invoice.status =='OPENED' && (invoice.paymentType == 'TICKET' || invoice.paymentType == 'TICKETS')"> 
            <img :src="invoice.urlTicket + '/letter.png?nocache='+ Math.random()"/>
            <br>
       </div> 
  </div>
</template>

<script>
const optionsAlert = {title: 'Mensagem', size: 'sm'}

export default {
  props : ['subscriptionId'],
  name: 'carne',
  components:{
  },
  mounted(){
     this.loadInvoiceData()
  },
  data(){
    return {
        invoices : null
    }
  },
  methods:{
     loadInvoiceData(){
        this.$clubApi.get('/subscription/'+this.subscriptionId+'/list/invoices')
        .then((response) => {
            this.invoices = response.data.object
        }) .catch((error) => {
            this.$dialogs.alert(error.response.data.msg, optionsAlert)
        }).finally(() =>{
            NProgress.done() 
        })
    },
    print(){
      window.print()
    },
    back(){
      window.close()
    }
  }
}
</script>

<style scoped>
  @media print {
      .noprint {
        display: none;
      }
  }
</style>